mapper.select:
SELECT e.id, e.category_id, c.name AS category_name, e.expense_date, e.amount, e.description, e.payment_method, e.memo, e.created_at, e.updated_at FROM expenses e INNER JOIN expense_categories c ON c.id = e.category_id
( e.description ILIKE CONCAT('%', #{keyword}, '%') OR e.memo ILIKE CONCAT('%', #{keyword}, '%') OR c.name ILIKE CONCAT('%', #{keyword}, '%') )
AND e.category_id = #{categoryId}
AND e.expense_date >= #{startDate}
AND e.expense_date <= #{endDate}
ORDER BY e.expense_date DESC, e.id DESC

SELECT COUNT(*)
FROM expenses
WHERE category_id = #{id}
